        CASE
            WHEN (COALESCE(i.input_total_kg, (0)::numeric) > (0)::numeric) THEN round(((100.0 * (((((((COALESCE(p.eu_prod_kg, (0)::numeric) + COALESCE(p.plus_prod_kg, (0)::numeric)) + COALESCE(p.carbon_black_kg, (0)::numeric)) + COALESCE(p.metal_scrap_kg, (0)::numeric)) + COALESCE(p.h2o_kg, (0)::numeric)) + COALESCE(p.gas_syngas_kg, (0)::numeric)) + COALESCE(p.losses_kg, (0)::numeric)) - i.input_total_kg)) / i.input_total_kg), 4)
            ELSE NULL::numeric
